cd ~/.openclaw/workspace/tools && .venv/bin/python3 -c "
import os, json
from supabase import create_client
url = os.environ['SUPABASE_URL']
key = os.environ['SUPABASE_SERVICE_KEY']
sb = create_client(url, key)
res = sb.table('sai_memory').select('content').eq('category', 'position_mastery').execute()

# Get structured entries with cluster info
structured = []
for r in res.data:
    try:
        c = json.loads(r['content']) if isinstance(r['content'], str) else r['content']
        if isinstance(c, dict) and c.get('cluster_family'):
            structured.append({
                'family': c.get('cluster_family',''),
                'cluster': c.get('cluster_name',''),
                'position': c.get('position_name','')
            })
    except:
        pass

# Show what clusters are covered
families = {}
for s in structured:
    f = s['family']
    if f not in families:
        families[f] = set()
    families[f].add(s['cluster'])

for f in sorted(families):
    print(f'\n=== {f} ===')
    for c in sorted(families[f]):
        positions = [s['position'] for s in structured if s['family'] == f and s['cluster'] == c]
        print(f'  {c}: {positions}')
"
